const e=JSON.parse(`[{"id":"abandoned-grove","name":"Abandoned Grove","tier":1,"type":"Exploration","description":"Un ancien bosquet druidique laissé en jachère et entièrement reconquis par la nature.","impulses":["Attirer les curieux","Faire écho au passé"],"difficulty":11,"potentialAdversaries":[{"group":"Beasts","names":["Bear","Dire Wolf","Glass Snake"]},{"group":"Grove Guardians","names":["Minor Treant","Sylvan Soldier","Young Dryad"]}],"features":[{"name":"Overgrown Battlefield","description":"Une bataille a eu lieu ici. Un PJ peut faire un jet d’Instinct pour identifier des preuves de ce combat. Sur un succès avec Espoir, apprenez les trois informations ci-dessous. Sur un succès avec Peur, apprenez-en deux. Sur un échec, un PJ peut cocher un Stress pour en apprendre une et gagner l’avantage sur le prochain jet d’action pour enquêter sur cet environnement. Un PJ avec un historique ou une Expérience appropriée peut apprendre un détail supplémentaire et poser une question de suivi sur la scène et obtenir une réponse véridique (même si pas toujours complète).\\n• Des traces de bataille (armes et branches brisées, entailles dans le sol) jonchent le terrain.\\n• Un tronc d’arbre couvert de mousse est en réalité le cadavre d’un tréant.\\n• Les arbres encore debout sont tordus de manière étrange, comme par une magie puissante.","questions":"Pourquoi ces groupes en sont-ils venus aux mains ? Pourquoi le bosquet est-il inutilisé maintenant ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Barbed Vines","description":"Choisissez un point dans le bosquet. Toutes les cibles à Portée Très Proche de ce point doivent réussir un jet de Réaction d’Agilité ou subir 1d8+3 dégâts physiques et devenir Entravées par des lianes barbelées. L’Entrave dure jusqu’à ce qu’elles soient libérées par un jet réussi de Finesse ou de Force ou en infligeant au moins 6 dégâts aux lianes.","questions":"Combien y a-t-il de lianes ? Où vous attrapent-elles ? Vous tirent-elles vers le bas ou vous soulèvent-elles du sol ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill","range":"veryClose"},{"name":"You Are Not Welcome Here","description":"Une Jeune Dryade, deux Sylvan Soldiers, et un nombre de Minor Treants égal au nombre de PJ apparaissent pour confronter le groupe pour leur intrusion.","questions":"Que dissimulent les gardiens du bosquet ? Quelle menace pour la forêt les PJ pourraient-ils affronter pour apaiser la Dryade ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Defiler","description":"Dépensez une Peur pour invoquer un Minor Chaos Elemental attiré par les échos de violence et de discorde. Il apparaît à Portée Lointaine d’un PJ choisi et passe immédiatement sous le projecteur.","questions":"De quelle couleur l’herbe devient-elle quand l’élémentaire apparaît ? Comment le chaos déforme-t-il les insectes et la petite faune dans le bosquet ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill","range":"far"}]},{"id":"ambushed","name":"Ambushed","tier":1,"type":"Event","description":"Une embuscade est tendue pour prendre un groupe imprudent au dépourvu.","impulses":["Submerger","Disperser","Encercler"],"difficulty":null,"difficultySpecial":"Égale celle de l’adversaire avec la Difficulté la plus élevée (voir Relative Strength).","potentialAdversaries":[{"group":null,"names":["Any"]}],"features":[{"name":"Relative Strength","description":"La Difficulté de cet environnement est égale à celle de l’adversaire avec la Difficulté la plus élevée.","questions":"Qui donne le signal de l’embuscade ? Qu’est-ce qui rend évident qu’il est aux commandes ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Surprise!","description":"Les embusqués se révèlent au groupe, vous gagnez 2 Peur, et le projecteur passe immédiatement à l’un des adversaires embusqués.","questions":"Que veulent les embusqués du groupe ? Comment leurs tactiques dans l’embuscade reflètent-elles cela ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"}]},{"id":"ambushers","name":"Ambushers","tier":1,"type":"Event","description":"Une embuscade est tendue par les PJ pour prendre des adversaires imprudents au dépourvu.","impulses":["S’échapper","Se regrouper","Protéger le plus vulnérable"],"difficulty":null,"difficultySpecial":"Égale celle de l’adversaire avec la Difficulté la plus élevée (voir Relative Strength).","potentialAdversaries":[{"group":null,"names":["Any"]}],"features":[{"name":"Relative Strength","description":"La Difficulté de cet environnement est égale à celle de l’adversaire avec la Difficulté la plus élevée.","questions":"Quel adversaire est le moins préparé ? Lequel l’est le plus ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Where Did They Come From?","description":"Quand un PJ lance l’embuscade sur des adversaires sans méfiance, vous perdez 2 Peur et le premier jet d’attaque d’un PJ a l’avantage.","questions":"Que faisaient les adversaires quand l’embuscade a commencé ? Comment cela influence-t-il leur approche du combat ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill"}]},{"id":"bustling-marketplace","name":"Bustling Marketplace","tier":1,"type":"Social","description":"Le cœur économique de la colonie, avec des artisans locaux, des marchands itinérants et des clients de toutes classes sociales.","impulses":["Acheter bas et vendre haut","Tenter et séduire avec des marchandises de près et de loin"],"difficulty":10,"potentialAdversaries":[{"group":"Guards","names":["Bladed Guard","Head Guard"]},{"group":null,"names":["Masked Thief","Merchant"]}],"features":[{"name":"Tip the Scales","description":"Les PJ peuvent gagner l’avantage sur un jet de Présence en offrant une poignée d’or dans le cadre de l’interaction.","questions":"N’importe quelle monnaie sera-t-elle acceptée, ou seulement la devise locale ? À quel point les PJ sont-ils ostensibles en offrant ce pot-de-vin ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Unexpected Find","description":"Révélez aux PJ que l’un des marchands possède quelque chose qu’ils veulent ou dont ils ont besoin, comme de la nourriture de chez eux, un livre rare, des composants magiques, une carte au trésor douteuse, ou une clé magique.","questions":"Quel prix au-delà de l’or le marchand demandera-t-il en échange de cette rareté ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Sticky Fingers","description":"Un voleur essaie de dérober quelque chose à un PJ. Le PJ doit réussir un jet d’Instinct pour remarquer le voleur ou perdre un objet au choix du MJ tandis que le voleur s’échappe à Portée Proche. Pour récupérer l’objet volé, les PJ doivent compléter un Progress Countdown (6) pour rattraper le voleur avant qu’il ne complète un Consequence Countdown (4) et ne s’échappe vers sa cachette.","questions":"Qu’est-ce qui a poussé cette personne au vol à la tire ? Où se trouve la cachette du voleur et comment a-t-elle échappé aux regards ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill","range":"close"},{"name":"Crowd Closes In","description":"Quand l’un des PJ se sépare du groupe, la foule se déplace et le coupe du reste du groupe.","questions":"Où le mouvement de la foule l’emporte-t-il ? Que ressent-il à être seul mais entouré ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill"}]},{"id":"cliffside-ascent","name":"Cliffside Ascent","tier":1,"type":"Traversal","description":"Une falaise escarpée et rocheuse suffisamment haute pour rendre la traversée dangereuse.","impulses":["Précipiter les imprudents vers une mort rocheuse","Attirer les gens avec la promesse de ce qui se trouve au sommet"],"difficulty":12,"potentialAdversaries":[{"group":null,"names":["Construct","Deeproot Defender","Giant Scorpion","Glass Snake"]}],"features":[{"name":"The Climb","description":"L’escalade de la falaise utilise un Progress Countdown (12). Il décrémente selon les critères suivants quand les PJ font un jet d’action pour grimper :\\n• Succès Critique : Décrémente de 3\\n• Succès avec Espoir : Décrémente de 2\\n• Succès avec Peur : Décrémente de 1\\n• Échec avec Espoir : Pas de progression\\n• Échec avec Peur : Incrémente de 1\\nQuand le countdown se déclenche, le groupe a atteint le sommet de la falaise.","questions":"En quelles formations étranges les pierres sont-elles disposées ? Quels avertissements sinistres les aventuriers précédents ont-ils laissés ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Pitons Left Behind","description":"Des grimpeurs précédents ont laissé de grandes tiges métalliques que les grimpeurs peuvent utiliser pour faciliter leur ascension. Si un PJ utilisant les pitons échoue un jet d’action pour grimper, il peut cocher un Stress au lieu d’incrémenter le countdown.","questions":"Que vous disent la forme et le matériau de ces pitons sur les grimpeurs précédents ? À quelle distance les uns des autres se trouvent-ils ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Fall","description":"Dépensez une Peur pour faire lâcher la prise d’un PJ, le précipitant vers le sol. S’il n’est pas sauvé lors de la prochaine action, il touche le sol et incrémente le countdown de 2. Le PJ subit 1d12 dégâts physiques si le countdown est entre 8 et 12, 2d12 entre 4 et 7, et 3d12 à 3 ou moins.","questions":"Comment peut-on voir que beaucoup d’autres sont tombés ici avant ? Qu’est-ce qui vit dans ces parois et pourrait effrayer les aventuriers pour un repas facile ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill"}]},{"id":"local-tavern","name":"Local Tavern","tier":1,"type":"Social","description":"Une taverne animée qui sert de centre social pour sa ville.","impulses":["Offrir des opportunités aux aventuriers","Nourrir la communauté"],"difficulty":10,"potentialAdversaries":[{"group":"Guards","names":["Bladed Guard","Head Guard"]},{"group":"Mercenaries","names":["Harrier","Sellsword","Spellblade","Weaponmaster"]},{"group":null,"names":["Merchant"]}],"features":[{"name":"What's the Talk of the Town?","description":"Un PJ peut interroger le barman, le personnel ou les clients sur les événements locaux, les rumeurs et le travail potentiel avec un jet de Présence. Sur un succès, il peut choisir deux des détails ci-dessous — ou trois en cas de succès critique. Sur un échec, il peut en choisir un et cocher un Stress tandis que le local bavarde sur quelque chose de non pertinent.\\n• Une rumeur fascinante en lien avec l’historique d’un PJ\\n• Un travail prometteur pour le groupe impliquant une menace ou situation proche\\n• Du folklore local en rapport avec quelque chose qu’ils ont vu\\n• Des ragots de ville qui suggèrent un problème communautaire","questions":"Qui détient quel type d’information ? Quels ragots les locaux commencent-ils à répandre sur les PJ ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Sing For Your Supper","description":"Un PJ peut se produire une fois devant les convives en faisant un jet de Présence. Sur un succès, il gagne 1d4 poignées d’or (2d4 en cas de succès critique). Sur un échec, il coche un Stress.","questions":"Quel morceau interprétez-vous ? Que signifie ce morceau pour vous ? Quand l’avez-vous interprété pour la dernière fois devant un public ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Mysterious Stranger","description":"Révélez un étranger dissimulant son identité, tapi dans un box ombragé.","questions":"Que veut-il ? Quelle est son impression des PJ ? Quels manières ou accessoires a-t-il ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Someone Comes to Town","description":"Introduisez un PNJ important qui veut engager le groupe pour quelque chose ou qui a un lien avec l’historique d’un PJ.","questions":"Savait-il que les PJ étaient ici ? Que veut-il dans cette ville ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Bar Fight!","description":"Dépensez une Peur pour déclencher une bagarre dans la taverne. Quand un PJ essaie de traverser la taverne pendant que la bagarre persiste, il doit réussir un jet d’Agilité ou de Présence ou subir 1d6+2 dégâts physiques d’un coup sauvage ou d’un objet lancé. Un PJ peut essayer de déclencher cette feature en réussissant un jet d’action qui provoquerait les habitués de la taverne.","questions":"Qui a commencé la bagarre ? Que faudra-t-il pour l’arrêter ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill"}]},{"id":"outpost-town","name":"Outpost Town","tier":1,"type":"Social","description":"Une petite ville aux confins d’une nation ou région, proche d’un donjon, de tombeaux ou d’autres destinations d’aventure.","impulses":["Pousser les désespérés vers une mort certaine","Profiter d’un espoir en lambeaux"],"difficulty":12,"potentialAdversaries":[{"group":"Jagged Knife Bandits","names":["Hexer","Kneebreaker","Lackey","Lieutenant","Shadow","Sniper"]},{"group":null,"names":["Masked Thief","Merchant"]}],"features":[{"name":"Rumors Abound","description":"Les ragots sont la monnaie qui circule le plus vite dans le royaume. Un PJ peut se renseigner sur les événements majeurs en faisant un jet de Présence. Ce qu’il apprend dépend du résultat de son jet :\\n• Succès Critique : Apprenez deux événements majeurs. Le PJ peut poser une question de suivi sur l’une des rumeurs et obtenir une réponse véridique (même si pas toujours complète).\\n• Succès avec Espoir : Apprenez deux événements, dont au moins un en rapport avec l’historique du personnage.\\n• Succès avec Peur : Apprenez une rumeur alarmante en lien avec l’historique du personnage.\\n• Tout Échec : Les locaux réagissent mal à ses questions. Le PJ doit cocher un Stress pour apprendre une rumeur pertinente.","questions":"Quelles nouvelles les PJ ont-ils qu’ils pourraient transmettre aux voyageurs curieux ? Que pensent les locaux de ces événements ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Society of the Broken Compass","description":"Une société d’aventuriers maintient une maison de chapitre ici, où les héros échangent vantardises et rumeurs, boivent à leurs succès imaginés et complotent pour saper leurs rivaux.","questions":"Quelles vantardises les aventuriers ici font-ils, et lesquelles pensez-vous être vraies ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Rival Party","description":"Un autre groupe d’aventuriers est ici, cherchant le même trésor ou les mêmes pistes que les PJ.","questions":"Quel PJ a un lien avec l’un des membres du groupe rival ? Approchent-ils le PJ en premier ou attendent-ils que le PJ fasse le premier pas ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"It'd Be a Shame If Something Happened to Your Store","description":"Les PJ sont témoins tandis que des agents d’un boss du crime local rackettent un magasin de marchandises générales.","questions":"Quels ennuis cela cause-t-il si les PJ interviennent ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Wrong Place, Wrong Time","description":"La nuit, ou quand le groupe est seul dans une ruelle, vous pouvez dépenser une Peur pour introduire un groupe de voleurs qui tente de les détrousser.","questions":"Que cherchent les voleurs ? Que se passe-t-il si les PJ remettent ce qui est demandé ?","activationType":"reaction","cost":{"type":"fear","amount":1},"frequency":"atWill"}]},{"id":"raging-river","name":"Raging River","tier":1,"type":"Traversal","description":"Une rivière au courant rapide sans pont, assez profonde pour emporter la plupart des gens.","impulses":["Barrer le passage","Emporter les imprudents","Diviser la terre"],"difficulty":10,"potentialAdversaries":[{"group":"Beasts","names":["Bear","Glass Snake"]},{"group":"Jagged Knife Bandits","names":["Hexer","Kneebreaker","Lackey","Lieutenant","Shadow","Sniper"]}],"features":[{"name":"Dangerous Crossing","description":"Traverser la rivière nécessite que le groupe complète un Progress Countdown (4). Un PJ qui obtient un échec avec Peur est immédiatement ciblé par l’action « Undertow » sans nécessiter de dépenser une Peur pour la feature.","questions":"Des PJ ont-ils déjà traversé des rivières comme celle-ci ? Certains d’entre eux ont-ils peur de la noyade ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Undertow","description":"Dépensez une Peur pour attraper un PJ dans le courant sous-marin. Il doit faire un jet de Réaction d’Agilité. Sur un échec, il subit 1d6+1 dégâts physiques et est déplacé à Portée Proche en aval de la rivière, devenant Vulnérable jusqu’à ce qu’il sorte de la rivière. Sur un succès, il doit cocher un Stress.","questions":"Quels bibelots et babioles reposent au fond du lit de la rivière ? Des prédateurs nagent-ils dans ces eaux ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill","range":"close"},{"name":"Patient Hunter","description":"Dépensez une Peur pour invoquer un Glass Snake à Portée Proche d’un PJ choisi. Le serpent apparaît dans ou près de la rivière et passe immédiatement sous le projecteur pour utiliser son action « Spinning Serpent ».","questions":"Quels trésors la bête a-t-elle dans son terrier ? Quels voyageurs ont déjà été victimes de ce prédateur ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill","range":"close"}]}]`),s=JSON.parse('[{"id":"cult-ritual","name":"Cult Ritual","tier":2,"type":"Event","description":"Un culte tente de mener à bien un rituel ténébreux. Les PJ doivent intervenir avant que le rituel ne s’achève.","impulses":["Compléter le rituel","Convertir les intrus"],"difficulty":14,"potentialAdversaries":[{"group":"Cult of the Fallen","names":["Cult Adept","Cult Fang","Cult Initiate","Secret-Keeper"]}],"features":[{"name":"Desecrated Ground","description":"Les cultistes ont dédié ce lieu aux Dieux Déchus, et leur influence néfaste s’y infiltre. Réduisez le Dé d’Espoir des PJ à un d10 tant qu’ils sont dans cet environnement. La profanation peut être retirée avec un Progress Countdown (6).","questions":"Comment les PJ remarquent-ils en premier que quelque chose ne va pas dans ce lieu ? Quelles peurs refont surface quand l’espoir est maintenu à distance ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Blasphemous Might","description":"Une partie du pouvoir du rituel est détournée vers un membre du culte pour repousser les intrus. Choisissez un adversaire pour qu’il devienne Imprégné d’une magie terrible jusqu’à la fin de la scène ou sa défaite. Un adversaire Imprégné passe immédiatement sous le projecteur et gagne l’un des bénéfices suivants, ou les trois si vous dépensez une Peur :\\n• Il gagne l’avantage sur toutes ses attaques.\\n• Il inflige 1d10 dégâts supplémentaires sur une attaque réussie.\\n• Il gagne la feature suivante : Relentless (2) - Passive. Cet adversaire peut recevoir le projecteur jusqu’à deux fois par tour du MJ. Dépensez une Peur comme d’habitude pour lui donner le projecteur.","questions":"Comment l’ennemi change-t-il d’apparence ? Quelles peurs leurs coups font-ils remonter à la surface ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"The Summoning","description":"Countdown (6). Quand les PJ entrent dans la scène ou que le culte commence le rituel pour invoquer un démon, activez le countdown. Désignez un adversaire pour diriger le rituel. Le countdown se décrémente quand un PJ obtient un résultat avec Peur. Quand il se déclenche, invoquez un Minor Demon à Portée Très Proche du leader du rituel. Si le leader est vaincu, le countdown se termine sans effet car le rituel échoue.","questions":"Que fera le culte avec ce démon enchaîné s’il réussit ? Qu’essaieront-ils d’invoquer ensuite ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill","range":"veryClose"},{"name":"Complete the Ritual","description":"Si le leader du rituel est ciblé par une attaque ou un sort, un allié à Portée Très Proche de lui peut cocher un Stress pour être ciblé par cette attaque ou ce sort à sa place.","questions":"Que ressent-on en voyant une telle dévotion tournée vers la poursuite de la peur et de la domination ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill","range":"veryClose"}]},{"id":"hallowed-temple","name":"Hallowed Temple","tier":2,"type":"Social","description":"Un temple sacré dédié à une divinité bienveillante, offrant refuge et guérison à ceux qui le méritent.","impulses":["Purifier le souillé","Protéger le sacré","Éprouver la valeur des visiteurs"],"difficulty":13,"potentialAdversaries":[{"group":"Guards","names":["Archer Guard","Bladed Guard","Head Guard"]}],"features":[{"name":"A Place of Healing","description":"Un PJ qui prend un repos dans le Temple Sacré efface automatiquement tous ses PV.","questions":"Quelle est l’odeur de l’encens ? Quel genre de chants les acolytes entonnent-ils ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Divine Guidance","description":"Un PJ qui prie une divinité dans le Temple Sacré peut faire un jet d’Instinct pour recevoir des réponses. Si le dieu qu’il implore n’est pas bienvenu dans ce temple, le jet est fait avec un désavantage.\\n• Succès Critique : Le PJ obtient des informations claires. De plus, il gagne 1d4 Espoir, qui peuvent être répartis entre le groupe s’il partage la vision et les conseils reçus.\\n• Succès avec Espoir : Le PJ reçoit des informations claires.\\n• Succès avec Peur : Le PJ reçoit de brefs éclairs de compréhension et une impression émotionnelle transmettant une réponse.\\n• Tout Échec : Le PJ ne reçoit que des éclairs vagues. Il peut cocher un Stress pour recevoir une image claire sans contexte.","questions":"Que ressentez-vous en étant touché par cette vision ? Quel sentiment persiste après que les images se sont dissipées ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Relentless Hope","description":"Une fois par scène, chaque PJ peut cocher un Stress pour transformer un résultat avec Peur en un résultat avec Espoir.","questions":"À quelles émotions ou souvenirs vous raccrochez-vous quand la peur vous oppresse ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Divine Censure","description":"Quand les PJ ont transgressé, blasphémé ou offensé le clergé, vous pouvez dépenser une Peur pour invoquer un High Seraph et 1d4 Bladed Guards à Portée Proche du prêtre principal pour faire respecter leur volonté.","questions":"Quels symboles ou icônes portent-ils signalant qu’ils sont des agents consacrés de la divinité ? Qui dirige le groupe et qu’est-ce qui l’a mené à cette vocation ?","activationType":"reaction","cost":{"type":"fear","amount":1},"frequency":"atWill","range":"close"}]},{"id":"haunted-city","name":"Haunted City","tier":2,"type":"Exploration","description":"Une ville en ruines hantée par des esprits et des présences surnaturelles.","impulses":["Piéger les vivants","Rejouer les tragédies du passé"],"difficulty":14,"potentialAdversaries":[{"group":"Ghosts","names":["Spectral Archer","Spectral Captain","Spectral Guardian"]},{"group":null,"names":["Ghostly versions of other adversaries (see Ghostly Form)"]}],"features":[{"name":"Buried Knowledge","description":"La ville recèle d’innombrables mystères à découvrir. Un PJ qui cherche des connaissances sur la ville déchue peut faire un jet d’Instinct ou de Savoir pour en apprendre davantage et découvrir du butin (potentiellement hanté).\\n• Succès Critique : Obtenez une information précieuse et un objet utile lié.\\n• Succès avec Espoir : Obtenez une information précieuse.\\n• Succès avec Peur : Découvrez une information vague ou incomplète.\\n• Tout Échec : Cochez un Stress pour trouver une piste après une recherche exhaustive.","questions":"Quels secrets plus profonds la ville contient-elle ? Pourquoi tant de fantômes persistent-ils ici ? Quels aventuriers condamnés ont déjà connu un triste sort ici ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Ghostly Form","description":"Les adversaires qui apparaissent ici sont sous forme spectrale. Ils ont une résistance aux dégâts physiques et peuvent cocher un Stress pour se déplacer à Portée Proche à travers les objets solides.","questions":"Quelles blessures sur leur forme physique témoignent de leur cause de mort ? Quel but inachevé les retient dans le Plan Mortel ?","activationType":"passive","cost":{"type":"free","amount":0},"range":"close"},{"name":"Dead Ends","description":"Les fantômes d’une époque antérieure manifestent des scènes de leur ère révolue, comme un festival de rue, une révolution ou un cambriolage. Ces hantises modifient la disposition de la ville autour des PJ, bloquant le chemin derrière eux, forçant un détour, ou leur présentant un défi, comme les prendre pour des voleurs rivaux pendant le cambriolage.","questions":"Que veulent les fantômes de vous ? De quoi avez-vous besoin d’eux ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Apocalypse Then","description":"Dépensez une Peur pour manifester l’écho d’une catastrophe passée qui a ravagé la ville. Activez un Progress Countdown (5) tandis que la catastrophe se rejoue autour des PJ. Pour compléter le countdown et échapper à la catastrophe, les PJ doivent surmonter des menaces comme des incendies déchaînés, des civils en panique, des bâtiments qui s’effondrent ou des rues qui s’écroulent, tout en se remémorant l’histoire et en trouvant des indices pour échapper à l’inévitable.","questions":"Est-ce la catastrophe qui a conduit à l’abandon de la ville ? Que sait-on de cette catastrophe, et comment cela pourrait-il aider les PJ à s’échapper ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill"}]},{"id":"mountain-pass","name":"Mountain Pass","tier":2,"type":"Traversal","description":"Un col de montagne étroit et traître, exposé aux éléments et aux prédateurs qui rôdent dans les hauteurs.","impulses":["Isoler et diviser","Punir l’imprudence","Révéler la majesté de la nature"],"difficulty":15,"potentialAdversaries":[{"group":"Beasts","names":["Bear","Giant Eagle","Glass Snake"]},{"group":null,"names":["Chaos Skull","Minotaur Wrecker","Mortal Hunter"]}],"features":[{"name":"Engraved Sigils","description":"De grandes marques et gravures ont été faites dans le flanc de la montagne. Un PJ avec un historique ou une Expérience pertinente les identifie comme de la magie météorologique augmentant la puissance des vents glacials. Un PJ qui réussit un jet de Savoir peut se rappeler des informations sur les sigils, des informations potentielles sur leurs créateurs, et la connaissance de comment les dissiper. Si un PJ réussit un succès critique, il reconnaît que les sigils sont d’un style créé par des enchanteurs ridgeborne et il gagne l’avantage sur un jet pour dissiper les sigils.","questions":"Qui a posé cet enchantement ? Sont-ils proches ? Pourquoi voulaient-ils rendre le temps plus redoutable ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Avalanche","description":"Dépensez une Peur pour déclencher une avalanche. Tous les PJ doivent réussir un jet de Réaction d’Agilité ou subir 2d10+2 dégâts physiques et être ensevelis. Un PJ enseveli est Entravé et doit être déterré par ses alliés avec un jet réussi de Force.","questions":"Qu’est-ce qui a provoqué l’avalanche ? Des prédateurs profitent-ils du chaos pour attaquer ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill"},{"name":"Raptor Nest","description":"Quand les PJ entrent dans le territoire de chasse des rapaces, deux Giant Eagles apparaissent à Portée Très Lointaine d’un PJ choisi, identifiant les PJ comme une proie probable.","questions":"Depuis combien de temps les aigles n’ont-ils pas trouvé de proie ? Ont-ils des œufs dans leur nid, ou des jeunes qui ne volent pas encore ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill","range":"veryFar"},{"name":"Icy Winds","description":"Countdown (Boucle 4). Quand les PJ entrent dans le col de montagne, activez le countdown. Quand il se déclenche, tous les personnages traversant le col doivent réussir un jet de Réaction de Force ou cocher un Stress. Un PJ portant des vêtements appropriés pour le froid extrême gagne l’avantage sur ces jets.","questions":"Quelles parties du corps des PJ s’engourdissent en premier ? Comment essaient-ils de se réchauffer en avançant ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill"}]}]'),t=JSON.parse('[{"id":"burning-heart-of-the-woods","name":"Burning Heart of the Woods","tier":3,"type":"Exploration","description":"Un incendie de forêt magique ravage les bois, alimenté par une force surnaturelle qui le rend impossible à éteindre naturellement.","impulses":["Tout consumer","Forcer la fuite"],"difficulty":16,"potentialAdversaries":[{"group":"Beasts","names":["Bear","Glass Snake"]},{"group":"Elementals","names":["Elemental Spark"]},{"group":"Verdant Defenders","names":["Dryad","Oak Treant","Stag Knight"]}],"features":[{"name":"Chaos Magic Locus","description":"Quand un PJ fait un Spellcast Roll, il doit lancer deux Dés de Peur et prendre le résultat le plus élevé.","questions":"Que ressent-on en utilisant la magie dans ce lieu touché par le chaos ? Que craignez-vous qu’il arrive si vous perdez le contrôle du sort ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"The Indigo Flame","description":"Les PJ qui approchent l’arbre central peuvent faire un jet de Savoir pour tenter d’identifier la magie qui a consumé cet environnement.\\n• Sur un succès : Ils apprennent trois des détails ci-dessous. Sur un succès avec Peur, ils en apprennent deux.\\n• Sur un échec : Ils peuvent cocher un Stress pour en apprendre un et gagner l’avantage sur le prochain jet d’action pour enquêter sur cet environnement.\\n• Détails : C’est le résultat de magie des Déchus. La corruption se propage par la mousse cendrée. Elle ne peut être purifiée que par un rituel de magie naturelle avec un Progress Countdown (8).","questions":"Quel culte des Déchus a corrompu ces bois ? Qu’ont-ils déjà fait avec le bois maudit et la sève de cet arbre ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Grasping Vines","description":"Des lianes animées hérissées d’épines fouettent depuis les sous-bois pour enlacer les PJ. La cible doit réussir un jet de Réaction d’Agilité ou devenir Entravée et Vulnérable jusqu’à se libérer, annulant les deux conditions, avec un jet réussi de Finesse ou de Force ou en infligeant 10 dégâts aux lianes. Quand la cible fait un jet pour s’échapper, elle subit 1d8+4 dégâts physiques et perd un Espoir.","questions":"Quels souvenirs douloureux les lianes font-elles remonter à la surface en perçant la chair ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Charcoal Constructs","description":"Des animaux déformés enveloppés de flammes indigo piétinent un point de votre choix. Toutes les cibles à Portée Proche de ce point doivent faire un jet de Réaction d’Agilité. Les cibles qui échouent subissent 3d12+3 dégâts physiques. Les cibles qui réussissent subissent la moitié des dégâts.","questions":"Ces animaux sont-ils de vrais animaux consumés par la flamme ou simplement des constructions de la magie corruptrice ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill","range":"close"},{"name":"Choking Ash","description":"Countdown (Boucle). Quand les PJ entrent dans le Cœur Brûlant des Bois, activez le countdown. Quand il se déclenche, tous les personnages doivent faire un jet de Réaction de Force ou d’Instinct. Les cibles qui échouent subissent 4d6+5 dégâts physiques directs. Les cibles qui réussissent subissent la moitié des dégâts. Des masques ou vêtements de protection donnent l’avantage sur le jet de réaction.","questions":"Quelles hallucinations la cendre provoque-t-elle ? Quel goût incongru possède-t-elle ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill"}]},{"id":"castle-siege","name":"Castle Siege","tier":3,"type":"Event","description":"Un siège est en cours autour d’un château fortifié, que les PJ défendent ou attaquent.","impulses":["Briser les défenses","Épuiser les assiégés","Forcer la reddition"],"difficulty":17,"potentialAdversaries":[{"group":"Mercenaries","names":["Harrier","Sellsword","Spellblade","Weaponmaster"]},{"group":"Noble Forces","names":["Archer Squadron","Conscript","Elite Soldier","Knight of the Realm"]}],"features":[{"name":"Secret Entrance","description":"Un PJ peut trouver ou se rappeler un passage secret dans le château avec un jet réussi d’Instinct ou de Savoir.","questions":"Comment entrent-ils sans révéler le passage aux attaquants ? Des défenseurs surveillent-ils ce chemin ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Siege Weapons (Environment Change)","description":"Consequence Countdown (6). La force assiégeante déploie des armes de siège pour tenter de raser les fortifications des défenseurs. Activez le countdown quand le siège commence (pour un siège prolongé, utilisez un countdown à long terme). Quand il se déclenche, les fortifications des défenseurs ont été percées et les attaquants déferlent à l’intérieur. Vous gagnez 2 Peur, puis passez à l’environnement Pitched Battle et donnez-lui le projecteur.","questions":"Quelles armes de siège sont déployées ? Sont-elles magiques, ordinaires, ou un mélange des deux ? Quelles défenses les personnages doivent-ils surmonter pour prendre d’assaut le château ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Reinforcements!","description":"Invoquez un Knight of the Realm, un nombre de Minions de Tier 3 égal au nombre de PJ, et deux adversaires de votre choix à Portée Lointaine d’un PJ choisi comme renforts. Le Knight of the Realm passe immédiatement sous le projecteur.","questions":"Qui ciblent-ils en premier ? Quelle formation adoptent-ils ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill","range":"far"},{"name":"Collateral Damage","description":"Quand un adversaire est vaincu, vous pouvez dépenser une Peur pour qu’une attaque perdue d’une arme de siège frappe un point sur le champ de bataille. Toutes les cibles à Portée Très Proche de ce point doivent faire un jet de Réaction d’Agilité.\\n• Les cibles qui échouent subissent 3d8+3 dégâts physiques ou magiques et doivent cocher un Stress.\\n• Les cibles qui réussissent doivent cocher un Stress.","questions":"Quels débris sont dispersés par l’attaque ? Qu’est-ce qui est brisé par le coup et ne peut être facilement réparé ?","activationType":"reaction","cost":{"type":"fear","amount":1},"frequency":"atWill","range":"veryClose"}]},{"id":"pitched-battle","name":"Pitched Battle","tier":3,"type":"Event","description":"Une bataille rangée fait rage entre deux forces opposées, les PJ pris au milieu.","impulses":["Engloutir les PJ dans le chaos","Forcer des choix de camp"],"difficulty":17,"potentialAdversaries":[{"group":"Mercenaries","names":["Sellsword","Harrier","Spellblade","Weaponmaster"]},{"group":"Noble Forces","names":["Archer Squadron","Conscript","Elite Soldier","Knight of the Realm"]}],"features":[{"name":"Adrift on a Sea of Steel","description":"Traverser un champ de bataille pendant un combat actif est extrêmement dangereux. Un PJ doit réussir un jet d’Agilité pour se déplacer, et ne peut aller qu’à Portée Proche sur un succès. Si un adversaire est à Portée de Mêlée de lui, il doit cocher un Stress pour faire un jet d’Agilité pour se déplacer.","questions":"Les combattants vous prennent-ils pour l’ennemi ou vous considèrent-ils comme des intrus ? Pouvez-vous distinguer ami et ennemi dans la mêlée ?","activationType":"passive","cost":{"type":"free","amount":0},"range":"close"},{"name":"Raze and Pillage","description":"La force attaquante fait monter les enjeux en allumant un incendie, volant un bien précieux, kidnappant une personne importante, ou tuant la population.","questions":"Qu’est-ce qui a de la valeur ici ? Qui est le plus vulnérable ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"War Magic","description":"Dépensez une Peur quand un mage d’un camp utilise de la magie destructrice à grande échelle. Choisissez un point sur le champ de bataille à Portée Très Lointaine du mage. Toutes les cibles à Portée Proche de ce point doivent faire un jet de Réaction d’Agilité. Les cibles qui échouent subissent 3d12+8 dégâts magiques et doivent cocher un Stress.","questions":"Quelle forme prend l’attaque — boule de feu, pluie d’acide, tempête de lames ? Quel objectif tactique cette attaque vise-t-elle, et que se passe-t-il ensuite ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill","range":"veryFar"},{"name":"Reinforcements!","description":"Invoquez un Knight of the Realm, un nombre de Minions de Tier 3 égal au nombre de PJ, et deux adversaires de votre choix à Portée Lointaine d’un PJ choisi comme renforts. Le Knight of the Realm passe immédiatement sous le projecteur.","questions":"Qui ciblent-ils en premier ? Quelle formation adoptent-ils ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill","range":"far"}]}]'),n=JSON.parse(`[{"id":"chaos-realm","name":"Chaos Realm","tier":4,"type":"Traversal","description":"Un plan d’existence où la réalité elle-même est instable et en perpétuelle mutation.","impulses":["Déformer la perception","Défier la logique","Consumer les intrus"],"difficulty":20,"potentialAdversaries":[{"group":"Outer Realms Monstrosities","names":["Abomination","Corruptor","Thrall"]}],"features":[{"name":"Impossible Architecture","description":"Le haut est le bas, le bas est la droite, la droite mène aux étoiles. La gravité et la directionnalité elles-mêmes sont en flux, et toute tentative de se déplacer dans ce royaume est une odyssée en soi, nécessitant un Progress Countdown (8). Sur un échec, un PJ doit cocher un Stress en plus des autres conséquences du jet.","questions":"Que ressent-on en se déplaçant dans un espace si étranger au Plan Mortel ? Sur quel point de repère vous fixez-vous pour maintenir votre équilibre ? Quels repères bizarres traversez-vous dans votre voyage ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Everything You Are This Place Will Take from You","description":"Countdown (Boucle 1d4). Activez le countdown. Quand il se déclenche, tous les PJ doivent réussir un jet de Réaction de Présence ou leur trait le plus élevé est temporairement réduit de 1d4 à moins qu’ils ne cochent un nombre de Stress égal à sa valeur. Tout point de trait perdu est regagné si le PJ réussit un succès critique ou s’échappe du Royaume du Chaos.","questions":"Comment ce lieu tente-t-il de vous voler ce qui fait de vous une légende ? Que ressent-on quand ce pouvoir vous est arraché ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Unmaking","description":"Dépensez une Peur pour forcer un PJ à faire un jet de Réaction de Force. Sur un échec, il subit 4d10 dégâts magiques directs. Sur un succès, il doit cocher un Stress.","questions":"Quel aperçu d’autres mondes entrevoyez-vous tandis que ce lieu tente de vous défaire ? Quelle facette fondamentale de votre personnalité la défaisance tente-t-elle d’effacer ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill"},{"name":"Outer Realms Predators","description":"Dépensez une Peur pour invoquer un Outer Realms Abomination, un Outer Realms Corruptor, et 2d6 Outer Realms Thralls, qui apparaissent à Portée Proche d’un PJ choisi en défiance de toute logique et causalité. Donnez immédiatement le projecteur à l’un de ces adversaires, et vous pouvez dépenser une Peur supplémentaire pour réussir automatiquement l’attaque standard de cet adversaire.","questions":"Quels restes à demi-consumés du monde brisé ces monstruosités rejettent-elles en pourchassant la chair vivante ? Quels reflets déchiquetés d’une ancienne identité humaine entrevoyez-vous entre les moments de malveillance aveugle ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill","range":"close"},{"name":"Disorienting Reality","description":"Sur un résultat avec Peur, vous pouvez demander au PJ de décrire laquelle de ses peurs le Royaume du Chaos évoque tandis qu’une vision de la réalité se défait et se reconstitue devant lui. Le PJ perd un Espoir. Si c’est son dernier Espoir, vous gagnez une Peur.","questions":"Quel moment voient-ils ? Si c’est un souvenir, comment est-il déformé par ce lieu ? Sera-t-il difficile de s’accrocher au vrai souvenir ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill"}]},{"id":"divine-usurpation","name":"Divine Usurpation","tier":4,"type":"Event","description":"Un être mortel ou un demi-dieu tente d’usurper le pouvoir d’une divinité, menaçant l’équilibre cosmique.","impulses":["Achever l’ascension","Écraser toute opposition","Réécrire les lois de la réalité"],"difficulty":20,"potentialAdversaries":[{"group":null,"names":["Arch-Necromancer","Fallen Shock Troops","Mortal Hunter","Oracle of Doom","Perfected Zombie"]}],"features":[{"name":"Final Preparations","description":"Quand l’environnement passe sous le projecteur pour la première fois, désignez un adversaire comme l’Usurpateur cherchant à renverser les dieux. Activez un Long-Term Countdown (8) tandis que l’Usurpateur assemble ce dont il a besoin pour mener le rituel. Quand il se déclenche, donnez le projecteur à cet environnement pour utiliser la feature « Beginning of the End ». Tant que cet environnement reste en jeu, vous pouvez détenir jusqu’à 15 Peur.","questions":"De quoi l’Usurpateur a-t-il encore besoin : le cœur d’un High Seraph ? La pierre angulaire d’un ancien portail ? La loyauté de deux ennemis jurés ? Les larmes de chagrin d’une âme pure ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Divine Blessing","description":"Quand un PJ réussit un succès critique, il peut dépenser 2 Espoir pour rafraîchir une capacité normalement limitée par son nombre d’utilisations (comme une fois par repos, une fois par session).","questions":"Quel dieu vous favorise dans votre combat contre cette usurpation ? Comment votre pouvoir renouvelé reflète-t-il son influence ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Defilers Abound","description":"Dépensez 2 Peur pour invoquer 1d4+2 Fallen Shock Troops qui apparaissent à Portée Proche de l’Usurpateur pour assister son siège divin. Donnez immédiatement le projecteur aux Shock Troops pour utiliser une action « Group Attack ».","questions":"Quel High Fallen ces troupes servent-elles ? La chair de quel dieu souhaitent-elles festoyer ?","activationType":"action","cost":{"type":"fear","amount":2},"frequency":"atWill","range":"close"},{"name":"Godslayer","description":"Si le Divine Siege Countdown (voir « Beginning of the End ») s’est déclenché, vous pouvez dépenser 3 Peur pour décrire l’Usurpateur tuant l’un des dieux des Hallows Above, se repaissant de leur pouvoir et devenant plus fort. L’Usurpateur efface 2 PV. Augmentez sa Difficulté, ses dégâts, son modificateur d’attaque, ou donnez-lui une nouvelle feature du dieu tué.","questions":"Quel dieu rencontre sa fin ? Quels sont ses derniers mots ? Comment le nouveau pouvoir volé de l’Usurpateur se manifeste-t-il ?","activationType":"action","cost":{"type":"fear","amount":3},"frequency":"atWill"},{"name":"Beginning of the End","description":"Quand le countdown « Final Preparations » se déclenche, l’Usurpateur commence à marteler les portes des Hallows eux-mêmes. Activez un Divine Siege Countdown (10). Donnez le projecteur à l’Usurpateur pour décrire son assaut et décrémenter ce countdown de 1. Si l’Usurpateur subit des dégâts Majeurs ou supérieurs, incrémentez le countdown de 1. Quand il se déclenche, l’Usurpateur brise la barrière entre le Plan Mortel et les Hallows Above pour tuer les dieux et prendre leur place. Vous gagnez une Peur pour chaque PV non marqué de l’Usurpateur. Vous pouvez immédiatement utiliser la feature « Godslayer » sans dépenser de Peur pour faire un mouvement de MJ supplémentaire.","questions":"Comment le Plan Mortel se tord-il tandis que l’ordre naturel est violé ? Quels mortels sont témoins de ce blasphème de loin ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill"},{"name":"Ritual Nexus","description":"Sur tout échec avec Peur contre l’Usurpateur, le PJ doit cocher 1d4 Stress à cause du contrecoup de la puissance magique.","questions":"Quelles visions d’échecs passés vous tourmentent quand vos efforts échouent ? Comment ces souvenirs sont-ils déformés par l’Usurpateur ?","activationType":"reaction","cost":{"type":"free","amount":0},"frequency":"atWill"}]},{"id":"imperial-court","name":"Imperial Court","tier":4,"type":"Social","description":"La cour impériale, où les intrigues politiques et les alliances fragiles déterminent le destin de nations.","impulses":["Manipuler et contrôler","Préserver les apparences"],"difficulty":20,"potentialAdversaries":[{"group":null,"names":["Bladed Guard","Courtesan","Knight of the Realm","Monarch","Spy"]}],"features":[{"name":"All Roads Lead Here","description":"Tant que les PJ sont à la Cour Impériale, un PJ a un désavantage sur les jets de Présence pour entreprendre des actions qui ne correspondent pas au mode de vie impérial ou ne soutiennent pas la domination de l’empire.","questions":"Comment l’utilisation du langage rend-elle difficile même de discuter de modes de vie alternatifs ? Quels avantages évidents de la loyauté créent des frictions quand vous essayez de proposer des alternatives ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Rival Vassals","description":"Les PJ peuvent trouver à la cour des sujets impériaux, des vassaux et des suppliants, chacun rivalisant pour les faveurs, cherchant la proximité du pouvoir, échangeant des services contre la loyauté, et élevant leur statut au-dessus des autres. Certains pourraient être désespérés de saper leurs rivaux, tandis que d’autres pourraient même être ouverts à des discussions qui frôlent la sédition.","questions":"Comment bénéficient-ils de la vassalité, et qu’est-ce que cela leur a coûté ? Quelle exploitation les pousse à envisager de s’opposer à l’imparable ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"The Gravity of Empire","description":"Dépensez une Peur pour présenter à un PJ une opportunité en or ou une offre de satisfaire un objectif majeur en échange de l’obéissance ou du soutien à l’empire. La cible doit faire un jet de Réaction de Présence. Sur un échec, elle doit cocher tout son Stress ou accepter l’offre. Si elle a déjà coché tout son Stress, elle doit accepter l’offre ou s’exiler de l’empire. Sur un succès, elle doit cocher 1d4 Stress car elle est mise à l’épreuve par la tentation.","questions":"Que désirent les PJ si désespérément qu’ils pourraient envisager de se rallier à ce pouvoir impitoyable ? Comment les agents impériaux ont-ils appris les désirs les plus profonds du PJ ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill"},{"name":"Imperial Decree","description":"Dépensez une Peur pour décrémenter de 1d4 un countdown à long terme lié à l’agenda de l’empire. Si cela déclenche le countdown, une proclamation liée à l’agenda est annoncée à la cour tandis que le plan est exécuté.","questions":"Quelle démonstration de pouvoir ou transfert de richesse a été nécessaire pour accélérer ce plan ? Quelles vies ont été perturbées ou bouleversées pour que cela se produise ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill"},{"name":"Eyes Everywhere","description":"Sur un résultat avec Peur, vous pouvez dépenser une Peur pour que quelqu’un de loyal à l’empire surprenne des propos séditieux à la cour. Un PJ doit réussir un jet de Réaction d’Instinct pour remarquer que le groupe a été entendu afin de tenter d’intercepter le témoin avant que les PJ ne soient démasqués.","questions":"Comment l’empire a-t-il compromis ce témoin ? Pourquoi son premier réflexe est-il de protéger l’empire, même s’il ne le traite pas bien ?","activationType":"reaction","cost":{"type":"fear","amount":1},"frequency":"atWill"}]},{"id":"necromancers-ossuary","name":"Necromancer's Ossuary","tier":4,"type":"Exploration","description":"Un ossuaire souterrain transformé en atelier par un nécromancien puissant, grouillant de morts-vivants et d’énergie nécrotique.","impulses":["Réanimer les morts","Absorber la force vitale","Protéger les recherches du nécromancien","Terrifier les intrus"],"difficulty":19,"potentialAdversaries":[{"group":"Arch-Necromancer's Host","names":["Perfected Zombie","Zombie Legion"]}],"features":[{"name":"No Place for the Living","description":"Une feature ou action qui efface des PV nécessite de dépenser un Espoir pour être utilisée. Si elle coûte déjà de l’Espoir, un PJ doit dépenser un Espoir supplémentaire.","questions":"Que ressent-on en essayant de guérir dans un lieu si antithétique à la vie ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Centuries of Knowledge","description":"Un PJ peut enquêter dans la bibliothèque et le laboratoire et faire un jet de Savoir pour apprendre des informations liées à l’arcane, l’histoire locale, et les plans du Nécromancien.","questions":"Quels sont les noms des tomes ? Sur quel projet le nécromancien travaille-t-il et que communique-t-il sur ses plans ?","activationType":"passive","cost":{"type":"free","amount":0}},{"name":"Skeletal Burst","description":"Toutes les cibles à Portée Proche d’un point de votre choix dans cet environnement doivent réussir un jet de Réaction d’Agilité ou subir 4d8+8 dégâts physiques des éclats de squelette tandis qu’une partie de l’ossuaire détone autour d’elles.","questions":"Quelle ancienne architecture osseuse est détruite ? Quels os se plantent dans votre armure ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill","range":"close"},{"name":"Aura of Death","description":"Une fois par scène, lancez un d4. Chaque mort-vivant à Portée Lointaine du Nécromancien peut effacer des PV et du Stress égaux au résultat lancé. Le mort-vivant peut choisir comment ce nombre est réparti entre PV et Stress.","questions":"Comment leur vigueur renouvelée se manifeste-t-elle ? Ont-ils l’air plus vivants ou, paradoxalement, plus décomposés mais vigoureux ?","activationType":"action","cost":{"type":"free","amount":0},"frequency":"atWill","range":"far"},{"name":"They Just Keep Coming!","description":"Dépensez une Peur pour invoquer 1d6 Rotted Zombies, deux Perfected Zombies, ou une Zombie Legion, qui apparaissent à Portée Proche d’un PJ choisi.","questions":"Qui étaient ces personnes avant de devenir les pions du nécromancien ? Quels vestiges de ces vies restent visibles pour les héros ?","activationType":"action","cost":{"type":"fear","amount":1},"frequency":"atWill","range":"close"}]}]`),r=[...e,...s,...t,...n],i=["Exploration","Event","Social","Traversal"],a=[{value:1,label:"Tier 1",levels:"1"},{value:2,label:"Tier 2",levels:"2–4"},{value:3,label:"Tier 3",levels:"5–7"},{value:4,label:"Tier 4",levels:"8–10"}],u={Exploration:"🔍",Event:"⚡",Social:"🗣️",Traversal:"🥾"},o={Exploration:"Exploration",Event:"Événement",Social:"Social",Traversal:"Traversée"};export{o as E,a as T,u as a,i as b,r as c};
